async (params, browser) => {
  // Open Glassdoor reviews page
  await browser.open(`${params.reviews_url}`)

  // Wait for reviews to load
  await browser.waitForSelector('.review-details, [data-test="review-details"], .empReview, .gdReview, .review_overview', 15000)

  // Let reviews render
  await browser.wait(2500)

  // Scroll to load more reviews
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Continue scrolling
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract company reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('.review-details, [data-test="review-details"], .empReview, .gdReview, .review_overview, [id^="empReview"]'); for (let i = 0; i < Math.min(reviewEls.length, 15); i++) { const rev = reviewEls[i]; const titleEl = rev.querySelector('.reviewLink, [data-test="review-title"], .review-title, .summary, a.reviewLink, h2 a'); const ratingEl = rev.querySelector('.ratingNumber, [data-test="rating"], .rating .value-title, span[class*="ratingNum"]'); const prosEl = rev.querySelector('[data-test="pros"], .pros, .review-pros span, [class*="reviewBodyCell"] span:nth-of-type(1)'); const consEl = rev.querySelector('[data-test="cons"], .cons, .review-cons span, [class*="reviewBodyCell"] span:nth-of-type(2)'); const roleEl = rev.querySelector('.authorJobTitle, [data-test="review-employee-role"], .reviewer-job-title, [class*="authorJobTitle"], .reviewAuthor'); const dateEl = rev.querySelector('.reviewDate, [data-test="review-date"], .review-date, [class*="reviewDate"], time, .date'); const statusEl = rev.querySelector('.pt-xsm, .mainText, [data-test="review-employee-status"], .reviewAuthor, [class*="employmentStatus"]'); reviews.push({ title: titleEl ? titleEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', pros: prosEl ? prosEl.textContent.trim().slice(0, 500) : '', cons: consEl ? consEl.textContent.trim().slice(0, 500) : '', role: roleEl ? roleEl.textContent.trim() : '', date: dateEl ? dateEl.textContent.trim() : '', status: statusEl ? statusEl.textContent.trim() : '' }); } const overallRatingEl = document.querySelector('[data-test="rating-info"], .ratingNum, .rating-num'); return { overall_rating: overallRatingEl ? overallRatingEl.textContent.trim() : '', review_count: reviews.length, reviews: reviews, reviews_url: window.location.href }`)

  return reviews_data
}
